package com.example.fileupload.config;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.annotation.Configuration;
import org.springframework.web.servlet.config.annotation.ResourceHandlerRegistry;
import org.springframework.web.servlet.config.annotation.WebMvcConfigurer;

import java.nio.file.Paths;

@Configuration
public class MvcConfig implements WebMvcConfigurer {

    private final StorageProperties storageProperties;

    @Autowired
    public MvcConfig(StorageProperties storageProperties) {
        this.storageProperties = storageProperties;
    }

    @Override
    public void addResourceHandlers(ResourceHandlerRegistry registry) {
        String uploadDir = storageProperties.getDir();
        String uploadUrlPrefix = storageProperties.getUrlPrefix();

        // Convert the relative path to an absolute path URL, prefixed with "file:/"
        String absolutePath = Paths.get(uploadDir).toAbsolutePath().toUri().toString();

        registry.addResourceHandler(uploadUrlPrefix + "**")
                .addResourceLocations(absolutePath);
    }
}

