package com.example.fileupload.controller;

import com.example.fileupload.service.StorageService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.multipart.MultipartFile;
import org.springframework.web.servlet.support.ServletUriComponentsBuilder;

import java.util.HashMap;
import java.util.Map;

@RestController
@RequestMapping("/api/upload")
public class FileUploadController {

    private final StorageService storageService;

    @Autowired
    public FileUploadController(StorageService storageService) {
        this.storageService = storageService;
    }

    @PostMapping("/profile-picture")
    public ResponseEntity<Map<String, String>> uploadProfilePicture(@RequestParam("file") MultipartFile file) {
        String storedFilename = storageService.store(file);
        String relativeFileUrl = storageService.getFileUrl(storedFilename);

        // Construct the full absolute URL for the stored file
        String fullFileUrl = ServletUriComponentsBuilder.fromCurrentContextPath()
                .path(relativeFileUrl)
                .toUriString();

        Map<String, String> response = new HashMap<>();
        response.put("message", "File uploaded successfully");
        response.put("fileUrl", fullFileUrl);

        return ResponseEntity.ok(response);
    }
}

